+            blocked_categories: HashSet::new(),
+        }
+    }
+
+    /// Read-only policy: may read tickets but not suggest or apply.
+    #[must_use]
+    pub fn new_readonly() -> Self {
+        Self {
+            allow_read: true,
+            allow_suggest: false,
+            allow_auto_apply: false,
+            require_approval_for_apply: true,
+            blocked_categories: HashSet::new(),
+        }
